if (!function_exists('update_user_level_gamification')) {
    function update_user_level_gamification($pdo, $user_id) {
        $user_id = (int)$user_id;
        $pdo->prepare("UPDATE users SET level = GREATEST(1, FLOOR(points / 5) + 1) WHERE id = ?")->execute([$user_id]);
    }
}

if (!function_exists('apply_tweet_gamification')) {
    function apply_tweet_gamification($pdo, $user_id, $is_delete = false) {
        $user_id = (int)$user_id;
        if ($is_delete) {
            $pdo->prepare("UPDATE users SET points = GREATEST(0, points - 1) WHERE id = ?")->execute([$user_id]);
        } else {
            $pdo->prepare("UPDATE users SET points = points + 1 WHERE id = ?")->execute([$user_id]);
        }
        update_user_level_gamification($pdo, $user_id);
    }
}

if (!function_exists('apply_tweet_like_gamification')) {
    function apply_tweet_like_gamification($pdo, $author_id, $is_unlike = false) {
        $author_id = (int)$author_id;
        
        $stmt = $pdo->prepare("SELECT COUNT(l.id) FROM likes l JOIN tweets t ON l.tweet_id = t.id WHERE t.user_id = ?");
        $stmt->execute([$author_id]);
        $total_likes_after_action = (int)$stmt->fetchColumn();

        $points_from_likes_after = floor($total_likes_after_action / 10);
        
        if ($is_unlike) {
            $total_likes_before_action = $total_likes_after_action + 1;
        } else {
            $total_likes_before_action = $total_likes_after_action - 1;
        }
        $points_from_likes_before = floor($total_likes_before_action / 10);

        $points_diff = (int)($points_from_likes_after - $points_from_likes_before);

        if ($points_diff !== 0) {
            $pdo->prepare("UPDATE users SET points = GREATEST(0, points + ?) WHERE id = ?")->execute([$points_diff, $author_id]);
            update_user_level_gamification($pdo, $author_id);
        }
    }
}

if (!function_exists('apply_jozve_like_gamification')) {
    function apply_jozve_like_gamification($pdo, $author_id, $points_diff) {
        $author_id = (int)$author_id;
        $points_diff = (int)$points_diff;
        if ($points_diff !== 0) {
            $pdo->prepare("UPDATE users SET points = GREATEST(0, points + ?) WHERE id = ?")->execute([$points_diff, $author_id]);
            update_user_level_gamification($pdo, $author_id);
        }
    }
}

if (!function_exists('apply_jozve_view_gamification')) {
    function apply_jozve_view_gamification($pdo, $author_id, $total_views) {
        $author_id = (int)$author_id;
        $total_views = (int)$total_views;
        if ($total_views > 0 && $total_views % 10 === 0) {
            $pdo->prepare("UPDATE users SET points = points + 1 WHERE id = ?")->execute([$author_id]);
            update_user_level_gamification($pdo, $author_id);
        }
    }
}
